        /**
         * Performs some general consolidations of inconsistencies on the given score like
         * missing bars, beats, duplicated midi channels etc
         */
        @kotlin.jvm.JvmStatic
        public fun consolidate(score: com.omnifret.gplayer.model.Score): Unit{
            if (score.masterBars.length == 0.0)
            {
                var master: com.omnifret.gplayer.model.MasterBar = com.omnifret.gplayer.model.MasterBar()
                score.addMasterBar(master)
                var tempoAutomation: com.omnifret.gplayer.model.Automation = com.omnifret.gplayer.model.Automation()
                tempoAutomation.isLinear = false
                tempoAutomation.type = com.omnifret.gplayer.model.AutomationType.Tempo
                tempoAutomation.value = score.tempo
                master.tempoAutomations.push(tempoAutomation)
                var bar: com.omnifret.gplayer.model.Bar = com.omnifret.gplayer.model.Bar()
                score.tracks[(0).toInt()].staves[(0).toInt()].addBar(bar)
                var v: com.omnifret.gplayer.model.Voice = com.omnifret.gplayer.model.Voice()
                bar.addVoice(v)
                var emptyBeat: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
                emptyBeat.isEmpty = true
                v.addBeat(emptyBeat)
                return
            }
            var usedChannels: com.omnifret.gplayer.core.ecmaScript.Set<Double> = com.omnifret.gplayer.core.ecmaScript.Set<Double>(com.omnifret.gplayer.collections.SimpleIterable<Double>(
                com.omnifret.gplayer.synth.SynthConstants.PercussionChannel)
            )
            for (track in score.tracks)
            {
                if (track.staves.length == 1.0 && track.staves[(0).toInt()].isPercussion)
                {
                    track.playbackInfo.primaryChannel = com.omnifret.gplayer.synth.SynthConstants.PercussionChannel
                    track.playbackInfo.secondaryChannel = com.omnifret.gplayer.synth.SynthConstants.PercussionChannel
                }
                else 
                {
                    if (track.playbackInfo.primaryChannel != com.omnifret.gplayer.synth.SynthConstants.PercussionChannel)
                    {
                        while (usedChannels.has(track.playbackInfo.primaryChannel))
                        {
                            track.playbackInfo.primaryChannel++
                        }
                    }
                    usedChannels.add(track.playbackInfo.primaryChannel)
                    if (track.playbackInfo.secondaryChannel != com.omnifret.gplayer.synth.SynthConstants.PercussionChannel)
                    {
                        while (usedChannels.has(track.playbackInfo.secondaryChannel))
                        {
                            track.playbackInfo.secondaryChannel++
                        }
                    }
                    usedChannels.add(track.playbackInfo.secondaryChannel)
                }
                for (staff in track.staves)
                {
                    for (b in staff.bars)
                    {
                        for (v in b.voices)
                        {
                            if (v.isEmpty && v.beats.length == 0.0)
                            {
                                var emptyBeat: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
                                emptyBeat.isEmpty = true
                                v.addBeat(emptyBeat)
                            }
                        }
                    }
                    var voiceCount: Double = if(staff.bars.length == 0.0)  1.0 else staff.bars[(0).toInt()].voices.length
                    while (staff.bars.length < score.masterBars.length)
                    {
                        var bar: com.omnifret.gplayer.model.Bar = com.omnifret.gplayer.model.Bar()
                        staff.addBar(bar)
                        var previousBar: com.omnifret.gplayer.model.Bar? = bar.previousBar
                        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(previousBar)))
                        {
                            bar.clef = previousBar!!.clef
                            bar.clefOttava = previousBar!!.clefOttava
                            bar.keySignature = bar.previousBar!!.keySignature
                            bar.keySignatureType = bar.previousBar!!.keySignatureType
                        }
                        if (true) {
                            var i: Double = 0.0
                            
                            while(i < voiceCount){
                                var v: com.omnifret.gplayer.model.Voice = com.omnifret.gplayer.model.Voice()
                                bar.addVoice(v)
                                var emptyBeat: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
                                emptyBeat.isEmpty = true
                                v.addBeat(emptyBeat)
                                i++
                            }
                        }
                    }
                }
            }
            if (score.masterBars.length > 0)
            {
                var firstTempoAutomation: com.omnifret.gplayer.model.Automation? = score.masterBars[(0).toInt()].tempoAutomations.find(fun(a: com.omnifret.gplayer.model.Automation): Boolean{
                    return a.type == com.omnifret.gplayer.model.AutomationType.Tempo && a.ratioPosition == 0.0
                }
                )
                if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(firstTempoAutomation)))
                {
                    var tempoAutomation: com.omnifret.gplayer.model.Automation = com.omnifret.gplayer.model.Automation()
                    tempoAutomation.isLinear = false
                    tempoAutomation.type = com.omnifret.gplayer.model.AutomationType.Tempo
                    tempoAutomation.value = score.tempo
                    tempoAutomation.text = score.tempoLabel
                    tempoAutomation.isVisible = false
                    score.masterBars[(0).toInt()].tempoAutomations.push(tempoAutomation)
                }
            }
        }
        
        /**
         * Trims any empty bars at the end of the song.
         */
        @kotlin.jvm.JvmStatic
        public fun trimEmptyBarsAtEnd(score: com.omnifret.gplayer.model.Score): Unit{
            while (score.masterBars.length > 1)
            {
                var barIndex: Double = score.masterBars.length - (1.0).toDouble()
                var masterBar: com.omnifret.gplayer.model.MasterBar = score.masterBars[(barIndex).toInt()]
                if (masterBar.hasChanges)
                {
                    return
                }
                for (track in score.tracks)
                {
                    for (staff in track.staves)
                    {
                        if (barIndex < staff.bars.length)
                        {
                            var bar: com.omnifret.gplayer.model.Bar = staff.bars[(barIndex).toInt()]
                            if (!bar.isEmpty || bar.hasChanges)
                            {
                                return
                            }
                        }
                    }
                }
                for (track in score.tracks)
                {
                    for (staff in track.staves)
                    {
                        if (barIndex < staff.bars.length)
                        {
                            var bar: com.omnifret.gplayer.model.Bar = staff.bars[(barIndex).toInt()]
                            staff.bars.pop()
                            bar.previousBar!!.nextBar = null
                        }
                    }
                }
                score.masterBars.pop()
                masterBar.previousMasterBar!!.nextMasterBar = null
            }
        }
        
